/* ─── feature config ──────────────────────────────────────────────────────── */

const FEATURES = [
  /* left column – label RIGHT of icon, so label comes first visually */
  {
    label: "Secure booking\nin minutes",
    icon: <IconBooking />,
    pos: "top-[7%] left-[20%]",
    side: "left" as const,
  },
  {
    label: "Professional drivers\nat your service",
    icon: <IconChauffeur />,
    pos: "top-[26%] left-[1%]",
    side: "left" as const,
  },
  {
    label: "Price vs Quality",
    icon: <IconQuality />,
    pos: "top-[55%] left-[-4%]", 
    side: "left" as const,
  },
  /* right column – label LEFT of icon */
  {
    label: "Multiple Luxury\nOption",
    icon: <IconDiamond />,
    pos: "top-[5%]  right-[20%]",
    side: "right" as const,
  },
  {
    label: "We care about\nyour safety\non your journey",
    icon: <IconSafety />,
    pos: "top-[26%] right-[4%]",
    side: "right" as const,
  },
  {
    label: "Available 24\nhours a day",
    icon: <IconClock24 />,
    pos: "top-[55%] right-[-3%]",
    side: "right" as const,
  },
];

/* ─── types ───────────────────────────────────────────────────────────────── */

type FleetSlideInteraction = {
  category: FleetCategory;
  slide: number;
  vehicleId?: string;
};

/* ─── page ────────────────────────────────────────────────────────────────── */

export function FleetDetailsPage() {
  const { vehicleId } = useParams<{ vehicleId: string }>();
  const vehicle = vehicleId ? getFleetVehicleById(vehicleId) : undefined;

  const [category] = useState<FleetCategory>(
    vehicle?.category ?? "All Vehicles",
  );
  const [interaction, setInteraction] = useState<FleetSlideInteraction | null>(
    null,
  );
  const [bookingModalOpen, setBookingModalOpen] = useState(false);

  const filtered = useMemo(
    () =>
      category === "All Vehicles"
        ? FLEET_VEHICLES
        : FLEET_VEHICLES.filter((v) => v.category === category),
    [category],
  );

  const slide = useMemo(() => {
    if (
      interaction &&
      interaction.category === category &&
      interaction.vehicleId === vehicleId
    ) {
      return interaction.slide;
    }
    if (!vehicleId) return 0;
    const index = filtered.findIndex((v) => v.id === vehicleId);
    return index >= 0 ? index : 0;
  }, [interaction, category, vehicleId, filtered]);

  const current = filtered[slide] ?? filtered[0];

  if (!vehicle) {
    return <Navigate to="/fleet" replace />;
  }

  return (
    <div className="overflow-hidden bg-white">
      <FleetHero tagline="UNMATCHED LUXURY" />

      {/* ── showcase section ── */}
      <section className="bg-white pt-16 lg:pt-44 max-md:pt-10">
        <div className="relative mx-auto h-[680px] max-w-[1200px] px-4 max-md:h-auto max-md:min-h-0 max-md:pb-24">
          {/* sage-green semicircle arch background */}
          <div
            className="absolute bottom-[120px] left-1/2 -translate-x-1/2 max-md:hidden"
            style={{
              width: "992.89px",
              height: "496.44px",
              background: "rgba(0, 39, 3, 0.2)",
              borderRadius: "496.44px 496.44px 0 0",
            }}
            aria-hidden
          />

          {/* feature badges */}
          {FEATURES.map((feat) => (
            <div
              key={feat.label}
              className={`absolute ${feat.pos} z-10 flex items-center gap-2.5 max-md:hidden`}
            >
              {/* left side: label → icon */}
              {feat.side === "left" && (
                <>
                  <p className="text-left font-lato text-[20px] font-semibold leading-snug text-maseer-green-text">
                    {feat.label.split("\n").map((line, i) => (
                      <span key={i}>
                        {line}
                        <br />
                      </span>
                    ))}
                  </p>
                  <div className="flex h-[82px] w-[82px] shrink-0 items-center justify-center rounded-full bg-[#002703] shadow-md">
                    {feat.icon}
                  </div>
                </>
              )}
              {/* right side: icon → label */}
              {feat.side === "right" && (
                <>
                  <div className="flex h-[82px] w-[82px] shrink-0 items-center justify-center rounded-full bg-[#002703] shadow-md">
                    {feat.icon}
                  </div>
                  <p className="text-left font-lato text-[20px] font-semibold leading-snug text-maseer-green-text">
                    {feat.label.split("\n").map((line, i) => (
                      <span key={i}>
                        {line}
                        <br />
                      </span>
                    ))}
                  </p>
                </>
              )}
            </div>
          ))}

          {/* car image centered over arch */}
          <div className="absolute bottom-[120px] left-1/2 w-[680px] -translate-x-1/2 max-md:relative max-md:bottom-auto max-md:w-full max-md:translate-x-0">
            {current && (
              <img
                src={current.image}
                alt={current.name}
                className="mx-auto h-[400px] w-[700px] object-contain drop-shadow-[0_20px_40px_rgba(0,0,0,0.18)] max-md:h-[200px] max-md:w-full max-md:max-w-[340px]"
              />
            )}
          </div>

          {/* CTA + dots — absolute at bottom center, overlapping arch base */}
          <div className="absolute bottom-5 left-1/2 -translate-x-1/2 text-center max-md:relative max-md:bottom-auto max-md:mt-6 max-md:translate-x-0">
            <button
              type="button"
              onClick={() => setBookingModalOpen(true)}
              className="btn-gold font-lato text-white"
            >
              Book this Vehicle 
              <span aria-hidden>→</span>
            </button>

            <div className="mt-4 flex items-center justify-center gap-2">
              {filtered.map((item, i) => (
                <button
                  key={item.id}
                  type="button"
                  aria-label={`Show ${item.name}`}
                  onClick={() =>
                    setInteraction({ category, slide: i, vehicleId })
                  }
                  className={[
                    "h-2.5 rounded-full transition-all duration-300",
                    slide === i
                      ? "w-8 bg-maseer-green"
                      : "w-2.5 bg-maseer-line hover:bg-maseer-muted/40",
                  ].join(" ")}
                />
              ))}
            </div>

            {current && (
              <p className="mt-3 font-serif text-xl font-semibold text-maseer-green-text">
                {current.name}
              </p>
            )}
          </div>
        </div>
      </section>

      <FleetStandards />
      <FleetCta buttonLabel="Book Your Vehicle Now" />

      <BookingModal
        isOpen={bookingModalOpen}
        onClose={() => setBookingModalOpen(false)}
        vehicleId={current?.id ?? vehicle.id}
        vehicleName={current?.name ?? vehicle.name}
      />
    </div>
  );
}
